sp_angular_provider.script:
function scmRefPicker($http, $timeout, scmFlyover) {
    "use_strict";
    return {
        restrict: "E",
        replace: true,
        require: "ngModel",
        scope: {
            label: "@",
            table: "@",
            displayField: "@",
            searchFields: "@?",
            placeholder: "@?",
            referenceQualifier: "@?",
            pageSize: "@?",
            minimumInputLength: "@?",
            displayFields: "@?",
            orderBy: "@?",
            orderDirection: "@?",
            advancedSearchListProvider: "@?",
        },

        template: `
            <div class="scm-reference-wrapper">
                <label
                    for="{{uid}}">
                    {{ label }}
                </label>
                <div class="scm-reference-input-wrapper">
                    <input 
                        class="input scm-reference-input"
                        ng-class="{'scm-reference-list-open': showResults}"
                        id="{{displayUid}}"
                        type="text"
                        ng-model="displayValue"
                        ng-click="openList()"
                        placeholder="{{ placeholder || 'Select an option' }}"
                    >
                    <a
                        ng-if="displayValue"
                        ng-click="clearSelection()"
                        class="scm-reference-clear-icon">
                        <sdx-icon 
                            icon-name="icon-close" 
                            size="1">
                        </sdx-icon>
                    </a>
                    </input>
                    <sdx-icon 
                        class="scm-reference-magnifying-glass-icon" 
                        icon-name="icon-search" size="3"
                        ng-click="openFlyover()">
                    </sdx-icon>
                </div>
                <div class="scm-reference-dropdown-container" ng-show="showResults">
                    <div class="scm-reference-search-wrapper">
                    <input
                        id="{{searchUid}}"
                        type="text"
                        ng-model="searchTerm"
                        ng-model-options="{debounce: 300}"
                        ng-blur="closeList()"
                        ng-change="onSearch()"
                        ng-keydown="handleKeyDown($event)"
                        placeholder="Type to search..."
                        class="input scm-reference-search-input"
                    />
                    </div>
                    <ul class="scm-autocomplete-list">
                        <li 
                            class="scm-autocomplete-item"
                            ng-repeat="item in results track by item.sysId"
                            ng-mousedown="selectItem(item)">
                            {{ item.displayList }}
                        </li>
                        <li
                            class="scm-autocomplete-item scm-autocomplete-load-more"
                            ng-if="moreResults && !isLoading"
                            ng-mousedown="loadMore()">
                            Load more results...
                        </li>
                        <li
                            class="scm-autocomplete-item scm-autocomplete-loading"
                            ng-if="isLoading">
                            Loading...
                        </li>
                        <li
                            class="scm-autocomplete-item scm-autocomplete-no-results"
                            ng-if="results.length == 0 && !isLoading">
                            No results...
                        </li>
                        <li
                            class="scm-autocomplete-item scm-autocomplete-no-more"
                            ng-if="!moreResults && results.length && !isLoading">
                            No more results...
                        </li>
                    </ul>
                </div>
            </div>
            `,
        controller: ($scope, $http, spUtil) => {
            if (!$scope.label || !$scope.table || !$scope.displayField) {
                console.error(
                    "scmRefPicker: Missing required attributes. Please provide label, table, and displayField.",
                );
                return;
            }

            $scope.displayUid = spUtil.createUid("xxxx-xxxx");
            $scope.searchUid = spUtil.createUid("xxxx-xxxx");

            $scope.isLoading = false;
            $scope.moreResults = false;
            $scope.searchTerm = "";
            $scope.displayValue = "";
            $scope.showResults = false;
            $scope.results = [];

            const table = $scope.table;
            const displayField = $scope.displayField;
            const searchFields = $scope.searchFields || $scope.displayField;
            const displayFields = $scope.displayFields || $scope.displayField;
            const referenceQualifier = $scope.referenceQualifier || "";
            const pageSize = $scope.pageSize
                ? parseInt($scope.pageSize, 10)
                : 10;
            const minCharts = $scope.minimumInputLength
                ? parseInt($scope.minimumInputLength, 10)
                : 2;
            const orderBy = $scope.orderBy ? $scope.orderBy.trim() : "sys_id";
            const orderDirection =
                $scope.orderDirection &&
                ["asc", "desc"].includes($scope.orderDirection.toLowerCase())
                    ? $scope.orderDirection.toLowerCase()
                    : "asc";

            let page = 0;

            $scope.loadMore = () => {
                loadMore();
            };

            $scope.onSearch = () => {
                search();
            };

            $scope.fetchPage = () => {
                fetchPage();
            };

            $scope.fetchDisplayValue = (sysId) => {
                fetchDisplayValue(sysId);
            };

            function loadMore() {
                page++;
                fetchPage();
            }

            function search() {
                $scope.results = [];
                $scope.moreResults = false;

                if (
                    !$scope.searchTerm ||
                    $scope.searchTerm.length < minCharts
                ) {
                    return;
                }

                page = 0;
                fetchPage();
            }

            function buildQuery(term) {
                let searchConditions = [];

                const fields = searchFields.split(";").map((f) => f.trim());
                if (term) {
                    searchConditions = fields.map(
                        (field) => field + "CONTAINS" + term,
                    );
                }

                let finalQuery = searchConditions.join("^OR") || "";

                if (finalQuery && referenceQualifier) {
                    finalQuery = referenceQualifier + "^" + finalQuery;
                } else if (referenceQualifier) {
                    finalQuery = referenceQualifier;
                }

                if (orderDirection === "asc") {
                    if (finalQuery) {
                        finalQuery += "^ORDERBY" + orderBy;
                    } else {
                        finalQuery = "ORDERBY" + orderBy;
                    }
                } else {
                    if (finalQuery) {
                        finalQuery += "^ORDERBYDESC" + orderBy;
                    } else {
                        finalQuery = "ORDERBYDESC" + orderBy;
                    }
                }

                return finalQuery;
            }

            function fetchPage() {
                $scope.isLoading = true;

                let apiUrl = "/api/now/table/" + table;

                let params = [];

                params.push("sysparm_query=" + buildQuery($scope.searchTerm));

                params.push("sysparm_display_value=all");

                let fields = ["sys_id", displayField];
                fields = fields.concat(
                    displayFields.split(";").map((f) => f.trim()),
                );

                params.push(
                    "sysparm_fields=" + encodeURIComponent(fields.join(",")),
                );

                params.push("sysparm_limit=" + pageSize);
                params.push("sysparm_offset=" + page * pageSize);

                apiUrl += "?" + params.join("&");

                $http
                    .get(apiUrl)
                    .then((response) => {
                        if (response.data && response.data.result) {
                            const items = response.data.result;

                            const newResults = items.map((record) => {
                                let display = "";

                                let fields = displayFields
                                    .split(";")
                                    .map((field) => field.trim());
                                let displayValues = [];

                                fields.forEach(function (field) {
                                    if (
                                        record[field] &&
                                        record[field].display_value
                                    ) {
                                        displayValues.push(
                                            record[field].display_value,
                                        );
                                    }
                                });

                                display = displayValues.join(", ");

                                return {
                                    sysId: record.sys_id.display_value,
                                    displayList:
                                        display || record.sys_id.display_value,
                                    displaySelected:
                                        record[displayField].display_value,
                                };
                            });

                            $scope.results = $scope.results.concat(newResults);
                            $scope.moreResults = items.length === pageSize;
                            $scope.showResults = true;
                        }
                    })
                    .catch((error) => {
                        console.error(
                            "scmRefPicker: Error loading results",
                            error,
                        );
                        $scope.showResults = false;
                    })
                    .finally(() => {
                        $scope.isLoading = false;
                    });
            }

            function fetchDisplayValue(sysId) {
                if (!sysId) {
                    return;
                }

                let apiUrl = "/api/now/table/" + table + "/" + sysId;
                let params = ["sysparm_display_value=all"];

                let fields = ["sys_id", displayField];

                params.push(
                    "sysparm_fields=" + encodeURIComponent(fields.join(",")),
                );

                apiUrl += "?" + params.join("&");

                $http
                    .get(apiUrl)
                    .then((response) => {
                        if (response.data && response.data.result) {
                            $scope.displayValue =
                                response.data.result[
                                    displayField
                                ].display_value;
                        }
                    })
                    .catch((error) => {
                        console.error(
                            "scmRefPicker: Error loading display value",
                            error,
                        );
                    });
            }
        },

        link: (scope, element, attrs, ngModelCtrl) => {
            scope.ngModelCtrl = ngModelCtrl;

            ngModelCtrl.$render = function () {
                const sysId = ngModelCtrl.$viewValue;
                if (sysId) {
                    scope.fetchDisplayValue(sysId);
                } else {
                    scope.displayValue = "";
                }
            };

            scope.openList = () => {
                scope.showResults = true;

                if (scope.results.length === 0) {
                    scope.searchTerm = "";
                    scope.page = 0;
                    scope.fetchPage();
                }

                $timeout(() => {
                    angular.element("#" + scope.searchUid).focus();
                }, 0);
            };

            scope.openFlyover = () => {
                const flyover = new scmFlyover("scm-ref-picker-flyover", scope);
                flyover.setAppendToBody(true);
                flyover.setOptions({
                    tableProviderScriptInclude:
                        scope.advancedSearchListProvider,
                });
                flyover.setTitle("Advanced Search");
                scope.activeFlyover = flyover;
                flyover.open();
            };

            scope.$on("scmRefPicker:select", (e, params) => {
                const payload = params?.payload || {};

                if (
                    payload.targetDisplayUid &&
                    payload.targetDisplayUid !== scope.displayUid
                ) {
                    return;
                }

                if (!payload.sysId) {
                    return;
                }

                ngModelCtrl.$setViewValue(payload.sysId);
                scope.displayValue = payload.displayValue || "";
                scope.$applyAsync();

                if (
                    payload.closeFlyover === true &&
                    scope.activeFlyover &&
                    scope.activeFlyover.isOpen()
                ) {
                    scope.activeFlyover.close();
                }
            });

            scope.closeList = () => {
                if (scope.isLoading) {
                    return;
                }

                const list = element[0].querySelector(".scm-autocomplete-list");
                if (list) {
                    list.classList.remove("dropdown-up");
                }

                scope.results = [];
                scope.moreResults = false;
                scope.showResults = false;
                scope.searchTerm = "";
            };

            scope.selectItem = (item) => {
                ngModelCtrl.$setViewValue(item.sysId);
                scope.displayValue = item.displaySelected;
                scope.showResults = false;
                scope.moreResults = false;
                scope.results = [];
                scope.searchTerm = "";
            };

            scope.clearSelection = () => {
                ngModelCtrl.$setViewValue("");
                scope.displayValue = "";
            };

            scope.handleKeyDown = (event) => {
                switch (event.keyCode) {
                    case 27:
                        scope.closeList();
                        event.preventDefault();
                        break;
                }
            };
        },
    };
}
